output.sparql:
PREFIX wdt: <http://www.wikidata.org/prop/direct/>
PREFIX wd: <http://www.wikidata.org/entity/>
SELECT ?attendance WHERE {
  {
    ?game wdt:P361 wd:Q56692089 ; wdt:P1110 ?attendance
  } UNION {
    ?game wdt:P361 wd:Q14870260 ; wdt:P1110 ?attendance
  } UNION {
    ?game wdt:P361 wd:Q3511178 ; wdt:P1110 ?attendance
  }
}
ORDER BY DESC(?attendance)
LIMIT 1
OFFSET 2

